const memoryOptions = ["64GB", "128GB", "256GB", "512GB"];

export default async function ProductPage({ params }) {
  const { slug } = await params;
  const prouduct_res = await client.get(`product/slug/${slug}`);
  const product = prouduct_res?.data?.data;
  // console.log(product?.images);
  const imagePath = prouduct_res?.data?.meta?.image;
  // console.log(imagePath, " image path");
  // const [selectedColor, setSelectedColor] = useState(colors[0]);
  // const [selectedMemory, setSelectedMemory] = useState("128GB");

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-10 bg-white p-6 rounded-2xl shadow-lg">
        {/* Left - Images */}
        <div>
          <div className="rounded-xl overflow-hidden border">
            <img
              src={`http://localhost:5000/product/${product?.thumbnail}`}
              alt="product"
              width={500}
              height={500}
              className="object-contain w-full"
            />
          </div>

          <div className="flex gap-3 mt-4">
            {product?.images?.map((i) => (
              <div
                key={i}
                className="w-20 h-20 border rounded-lg flex items-center justify-center cursor-pointer hover:border-[#01A49E]"
              >
                <img
                  src={`http://localhost:5000/product/${i}`}
                  alt="thumb"
                  width={60}
                  height={60}
                />
              </div>
            ))}
          </div>
        </div>

        {/* Right - Details */}
        <div className="flex flex-col gap-5">
          <h1 className="text-2xl font-semibold">{product.name}</h1>

          <div className="flex items-center gap-3">
    <p className="text-2xl font-bold text-[#01A49E]">
      ₹{product?.final_price}
    </p>

    <>
      <p className="text-gray-400 line-through">
        ₹{product?.original_price}
      </p>

      <span className="bg-[#01A49E] text-white text-xs px-2 py-1 rounded">
        {product?.discount_percentage}% OFF
      </span>cd 
    </>
  </div>
          <ul className="text-sm text-gray-600 space-y-1">
            <li>• Intel LGA 1700 Socket</li>
            <li>• DDR5 Compatible</li>
            <li>• 16+1+2 Phase Digital VRM</li>
          </ul>

          {/* Color Selection */}
          <div>
            <h3 className="font-medium mb-2">Color</h3>
            <div className="flex gap-3">
              {product?.colorId?.map((color) => (
                <button
                  key={color.name}
                  className="px-4 py-2 border rounded-lg text-sm flex items-center gap-2 border-[#01A49E] bg-[#01A49E]/10"
                >
                  <span
                    className="w-4 h-4 rounded-full"
                    style={{ backgroundColor: color.colorCode }}
                  ></span>
                  {color.name}
                </button>
              ))}
            </div>
          </div>

          {/* Memory Selection */}
          {/* <div>
            <h3 className="font-medium mb-2">Memory Size</h3>
            <div className="flex gap-3">
              {memoryOptions.map((mem) => (
                <button
                  key={mem}
                  onClick={() => setSelectedMemory(mem)}
                  className={`px-4 py-2 border rounded-lg text-sm ${
                    selectedMemory === mem
                      ? "border-[#01A49E] bg-[#01A49E]/10"
                      : "border-gray-300"
                  }`}
                >
                  {mem}
                </button>
              ))}
            </div>
          </div> */}

          {/* Promo */}
          <div className="bg-[#01A49E]/10 p-4 rounded-xl text-sm">
            <p>
              Buy <span className="text-[#01A49E] font-semibold">02</span> boxes
              get a Snack Tray
            </p>
            <p>
              Buy <span className="text-[#01A49E] font-semibold">04</span> boxes
              get a free Block Toys
            </p>
          </div>

          {/* Buttons */}
          <div className="flex gap-4 mt-4">
            <AddToCartButton product = {product}/>
          </div>
        </div>
      </div>
    </div>
  );
}
